package com.ichi2.anki

import com.ichi2.anki.browser.CardBrowserViewModel
import com.ichi2.anki.preferences.SharedPreferencesProvider
import com.ichi2.testutils.EmptyApplication
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.hamcrest.Matchers.hasSize
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner
import org.robolectric.annotation.Config

@RunWith(RobolectricTestRunner::class)
@Config(application = EmptyApplication::class)
class CardBrowserSelectionToggleTest {

    /**
     * Test for the fix of issue: Card remains selected even after unselecting it
     * 
     * This test verifies that toggleRowSelectionAtPosition properly toggles
     * the selection state - selecting when unselected and unselecting when selected.
     */
    @Test
    fun toggleRowSelectionAtPosition_togglesSelectionCorrectly() {
        val viewModel = createViewModel()
        val cards = createTestCards(3)
        viewModel.cards.replaceWith(cards)

        // Initially, no cards should be selected
        assertThat(viewModel.selectedRowCount(), equalTo(0))

        // Select card at position 0
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat(viewModel.selectedRowCount(), equalTo(1))
        assertThat(viewModel.selectedCardIds, hasSize(1))
        assertThat(viewModel.selectedCardIds[0], equalTo(cards[0].id))

        // Select card at position 1
        viewModel.toggleRowSelectionAtPosition(1)
        assertThat(viewModel.selectedRowCount(), equalTo(2))
        assertThat(viewModel.selectedCardIds, hasSize(2))

        // Toggle (unselect) card at position 0 - this is the key test
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("Card at position 0 should be unselected", viewModel.selectedRowCount(), equalTo(1))
        assertThat(viewModel.selectedCardIds, hasSize(1))
        assertThat("Only card at position 1 should remain selected", viewModel.selectedCardIds[0], equalTo(cards[1].id))

        // Toggle (unselect) card at position 1
        viewModel.toggleRowSelectionAtPosition(1)
        assertThat("All cards should be unselected", viewModel.selectedRowCount(), equalTo(0))
    }

    /**
     * Test that multiple toggle operations work correctly
     */
    @Test
    fun toggleRowSelectionAtPosition_multipleTogglesCycle() {
        val viewModel = createViewModel()
        val cards = createTestCards(1)
        viewModel.cards.replaceWith(cards)

        // Initially unselected
        assertThat(viewModel.selectedRowCount(), equalTo(0))

        // First toggle - should select
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat(viewModel.selectedRowCount(), equalTo(1))

        // Second toggle - should unselect
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat(viewModel.selectedRowCount(), equalTo(0))

        // Third toggle - should select again
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat(viewModel.selectedRowCount(), equalTo(1))

        // Fourth toggle - should unselect again
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat(viewModel.selectedRowCount(), equalTo(0))
    }

    /**
     * Test the scenario described in the bug report:
     * Select a card, then select another card and unselect the first one.
     */
    @Test
    fun toggleRowSelectionAtPosition_bugReportScenario() {
        val viewModel = createViewModel()
        val cards = createTestCards(3)
        viewModel.cards.replaceWith(cards)

        // Step 1: Select first card
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("First card should be selected", viewModel.selectedRowCount(), equalTo(1))

        // Step 2: Select second card
        viewModel.toggleRowSelectionAtPosition(1)
        assertThat("Both cards should be selected", viewModel.selectedRowCount(), equalTo(2))

        // Step 3: Unselect first card (the bug was that it remained selected)
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("Only second card should be selected", viewModel.selectedRowCount(), equalTo(1))
        assertThat(viewModel.selectedCardIds[0], equalTo(cards[1].id))
    }

    private fun createViewModel(): CardBrowserViewModel {
        val preferencesProvider = object : SharedPreferencesProvider {
            override fun sharedPrefs() = AnkiDroidApp.instance.sharedPrefs()
        }
        return CardBrowserViewModel(preferencesProvider)
    }

    private fun createTestCards(count: Int): MutableList<CardBrowser.CardCache> {
        val cards = mutableListOf<CardBrowser.CardCache>()
        for (i in 0 until count) {
            cards.add(CardBrowser.CardCache(
                id = i.toLong(),
                isMarked = false,
                deck = "Test Deck",
                question = "Question $i",
                answer = "Answer $i",
                flags = 0
            ))
        }
        return cards
    }
}
"}

